import styled from "styled-components";
import A from "smart-react-components/element/A";
export default styled(A)(({ theme }) => `
    display: inline-block;
    color ${theme.src.color.darkblue};
    
    &:not([href]) {
        cursor: default;
        transition: opacity ${theme.util.anchorTransition};
        
        &:hover {
            opacity: .8;
        }
    }

    &[href] {
        &:hover {
            text-decoration: underline;
        }
    }
`);
